#include <iostream>
#include <string>

int main() {
  std::string text = "Hello, World!";
  char cstring[] = "Welcome";
  std::cout << "std::string: " << text << std::endl;
  std::cout << "C-style string: " << cstring << std::endl;
  return 0;
}
// Output:
// std::string: Hello, World!
// C-style string: Welcome

#include <iostream>
#include <string>

int main() {
  std::string text = "Hello, World!";
  std::cout << "Length: " << text.length() << std::endl;
  text.append(" Welcome!");
  std::cout << "Appended: " << text << std::endl;
  return 0;
}
// Output:
// Length: 13
// Appended: Hello, World! Welcome!

#include <iostream>
#include <cstring>

int main() {
  char text[] = "Hello";
  std::cout << "Length: " << strlen(text) << std::endl;
  return 0;
}
// Output:
// Length: 5

#include <iostream>
#include <string>

int main() {
  std::string text = "Programming in C++";
  std::string sub = text.substr(0, 11);
  std::cout << "Substring: " << sub << std::endl;
  size_t pos = text.find("C++");
  std::cout << "Position of C++: " << pos << std::endl;
  return 0;
}
// Output:
// Substring: Programming
// Position of C++: 14

